code = """import json
import re

# Load businesses
with open(locals()['var_function-call-2409580669065598132'], 'r') as f:
    businesses = json.load(f)

# Parse businesses to get State map and Sum review_count
state_stats = {} # state -> review_count_sum
us_states = {
    'AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD',
    'MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC',
    'SD','TN','TX','UT','VT','VA','WA','WV','WI','WY'
}

for b in businesses:
    desc = b.get('description', '')
    rc = int(b.get('review_count', 0))
    state = None
    
    # Try pattern "in City, ST"
    m = re.search(r"in [^,]+, ([A-Z]{2})", desc)
    if m and m.group(1) in us_states:
        state = m.group(1)
    
    if not state:
        # Fallback
        m = re.search(r", ([A-Z]{2})\b", desc)
        if m and m.group(1) in us_states:
            state = m.group(1)
            
    if state:
        if state not in state_stats:
            state_stats[state] = 0
        state_stats[state] += rc

# Sort
sorted_states = sorted(state_stats.items(), key=lambda x: x[1], reverse=True)

print("__RESULT__:")
print(json.dumps(sorted_states))"""

